interface.definition:
a!localVariables(
  local!attachment: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1520799"(
    eventId: ri!eventID,
    filteredFormat: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1524665"[1]
  ).data,
  /*attachmant List*/
  if(
    a!defaultValue(value: ri!showWhen, default: true),
    if(
      a!isNullOrEmpty(local!attachment),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        label: "Empty Message",
        labelPosition: "COLLAPSED",
        value: #"SYSTEM_SYSRULES_richTextItem_v1"(
          text: #"urn:appian:translation-string:v1:37e0bad3-b656-433a-9744-11372606b48c"
        )
      ),
      {
        #"SYSTEM_SYSRULES_checkboxField_v1"(
          choiceLabels: #"SYSTEM_SYSRULES_forEach"(
            local!attachment,
            fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/02925b99-1527-48bb-9fc8-406df81b2170"] & "." & fv!item[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/79c16d9b-9cce-4e0a-81bc-962f7bfc35e2"] 
          ),
          choiceValues: local!attachment[#"urn:appian:record-field:v1:17ccedd3-4c03-4664-8a75-fd71ae87f3ce/2e5753c4-e094-4e27-b8af-32c9447ddcbf"],
          value: ri!selected,
          saveInto: ri!selected
        ),
      }
    ),
    {}
  )
)
